   148→  async listWorktrees(): Promise<WorktreeListItem[]> {
   149→    const out = await this.git.raw(['worktree', 'list', '--porcelain'])
   150→    const lines = out.split('\n')
   151→    const items: WorktreeListItem[] = []
   152→    let current: Partial<WorktreeListItem> = {}
   153→    for (const line of lines) {
   154→      if (line.startsWith('worktree ')) {
   155→        if (current.path) items.push(current as WorktreeListItem)
   156→        current = { path: line.replace('worktree ', '').trim() }
   157→      } else if (line.startsWith('branch ')) {
   158→        current.branch = line.replace('branch refs/heads/', '').trim()
   159→      }
   160→    }
   161→    if (current.path) items.push(current as WorktreeListItem)
   162→    return items
   163→  }
