    20→/**
    21→ * Validates a pattern to ensure it doesn't escape the repository root
    22→ */
    23→function validatePattern(pattern: string): void {
    24→  // Remove leading '!' for exclusion patterns
    25→  const cleanPattern = pattern.startsWith('!') ? pattern.slice(1) : pattern
    26→
    27→  // Prevent directory traversal
    28→  if (cleanPattern.includes('../') || cleanPattern.startsWith('/')) {
    29→    throw new Error(`Invalid pattern: ${pattern}. Patterns must be relative to repo root.`)
    30→  }
    31→
    32→  // Warn about potentially sensitive files
    33→  const sensitivePatterns = [
    34→    /private.*key/i,
    35→    /\.pem$/,
    36→    /\.pfx$/,
    37→    /\.p12$/,
    38→    /password/i,
    39→    /secret/i,
    40→    /token/i,
    41→    /api.*key/i,
    42→  ]
    43→
    44→  for (const sensitive of sensitivePatterns) {
    45→    if (sensitive.test(cleanPattern)) {
    46→      console.warn(`⚠️  Pattern "${pattern}" may match sensitive files. Ensure proper security.`)
    47→    }
    48→  }
    49→}
