    51→/**
    52→ * Gets the list of ignored files that should be copied based on config patterns
    53→ */
    54→async function getIgnoredFilesToCopy(sourceRoot: string, patterns: string[]): Promise<string[]> {
    55→  // Read .gitignore file
    56→  let gitignoreContent = ''
    57→  try {
    58→    gitignoreContent = await fs.readFile(path.join(sourceRoot, '.gitignore'), 'utf-8')
    59→  } catch {
    60→    // No .gitignore file, so no files are ignored
    61→    return []
    62→  }
    63→
    64→  const ig = ignore().add(gitignoreContent)
    65→  const filesToCopy: Set<string> = new Set()
    66→  const excludePatterns: string[] = []
    67→
    68→  // Separate inclusion and exclusion patterns
    69→  for (const pattern of patterns) {
    70→    validatePattern(pattern)
    71→
    72→    if (pattern.startsWith('!')) {
    73→      excludePatterns.push(pattern.slice(1))
    74→    } else {
    75→      // Find matching files
    76→      const matches = await glob(pattern, {
    77→        cwd: sourceRoot,
    78→        dot: true,
    79→        absolute: false,
    80→        nodir: true, // Only match files, not directories
    81→      })
    82→
    83→      // Only include files that are actually ignored by git
    84→      for (const file of matches) {
    85→        if (ig.ignores(file)) {
    86→          filesToCopy.add(file)
    87→        }
    88→      }
    89→    }
    90→  }
    91→
    92→  // Remove excluded files
    93→  if (excludePatterns.length > 0) {
    94→    const excludeIg = ignore().add(excludePatterns)
    95→    for (const file of filesToCopy) {
    96→      if (excludeIg.ignores(file)) {
    97→        filesToCopy.delete(file)
    98→      }
    99→    }
   100→  }
   101→
   102→  return Array.from(filesToCopy)
   103→}
