   105→/**
   106→ * Copies ignored files from source to worktree based on config
   107→ */
   108→export async function copyIgnoredFiles(options: CopyIgnoredFilesOptions): Promise<CopyResult> {
   109→  const { sourceRoot, worktreeRoot, config, dryRun = false } = options
   110→  const result: CopyResult = {
   111→    copied: [],
   112→    skipped: [],
   113→    errors: [],
   114→  }
   115→
   116→  // Check if copying is configured
   117→  const patterns = config.worktree?.copyIgnoredFiles
   118→  if (!patterns || patterns.length === 0) {
   119→    return result
   120→  }
   121→
   122→  const copyFromPath = path.join(sourceRoot, config.worktree?.copyFromPath || '.')
   123→  const overwriteStrategy = config.worktree?.overwriteStrategy || 'skip'
   124→
   125→  console.log('🔍 Finding ignored files to copy...')
   126→
   127→  // Get list of files to copy
   128→  const files = await getIgnoredFilesToCopy(copyFromPath, patterns)
   129→
   130→  if (files.length === 0) {
   131→    console.log('No ignored files found matching patterns.')
   132→    return result
   133→  }
   134→
   135→  console.log(`Found ${files.length} file(s) to copy`)
   136→
   137→  for (const file of files) {
   138→    const sourcePath = path.join(copyFromPath, file)
   139→    const destPath = path.join(worktreeRoot, file)
   140→
   141→    try {
   142→      // Check if source exists
   143→      try {
   144→        await fs.access(sourcePath)
   145→      } catch {
   146→        console.warn(`⚠️  Source file not found: ${file}`)
   147→        result.errors.push({ file, error: 'Source file not found' })
   148→        continue
   149→      }
   150→
   151→      // Check if destination exists
   152→      let destExists = false
   153→      try {
   154→        await fs.access(destPath)
   155→        destExists = true
   156→      } catch {
   157→        // Destination doesn't exist, which is fine
   158→      }
   159→
   160→      if (destExists) {
   161→        switch (overwriteStrategy) {
   162→          case 'skip':
   163→            console.log(`⏭️  Skipping existing file: ${file}`)
   164→            result.skipped.push(file)
   165→            continue
   166→          case 'backup':
   167→            if (!dryRun) {
   168→              const backupPath = `${destPath}.backup.${Date.now()}`
   169→              await fs.rename(destPath, backupPath)
   170→              console.log(`💾 Backed up: ${file} -> ${path.basename(backupPath)}`)
   171→            } else {
   172→              console.log(`[DRY RUN] Would backup: ${file}`)
   173→            }
   174→            break
   175→          case 'overwrite':
   176→            console.log(`🔄 Overwriting: ${file}`)
   177→            break
   178→        }
   179→      }
   180→
   181→      if (!dryRun) {
   182→        // Ensure destination directory exists
   183→        const destDir = path.dirname(destPath)
   184→        await fs.mkdir(destDir, { recursive: true })
   185→
   186→        // Copy the file
   187→        await fs.copyFile(sourcePath, destPath)
   188→        console.log(`✅ Copied: ${file}`)
   189→      } else {
   190→        console.log(`[DRY RUN] Would copy: ${file}`)
   191→      }
   192→
   193→      result.copied.push(file)
   194→    } catch (error) {
   195→      const errorMsg = error instanceof Error ? error.message : String(error)
   196→      console.error(`❌ Failed to copy ${file}: ${errorMsg}`)
   197→      result.errors.push({ file, error: errorMsg })
   198→    }
   199→  }
   200→
   201→  // Print summary
   202→  console.log('\n📋 Copy Summary:')
   203→  console.log(`   Copied: ${result.copied.length} file(s)`)
   204→  if (result.skipped.length > 0) {
   205→    console.log(`   Skipped: ${result.skipped.length} file(s)`)
   206→  }
   207→  if (result.errors.length > 0) {
   208→    console.log(`   Errors: ${result.errors.length} file(s)`)
   209→  }
   210→
   211→  return result
   212→}
